fns.seltotext:
function seltotext(){
		var item = document.getElementById("_selIsout").value ;
//		var param = '_hidDeptNO='+document.getElementById("_selDeptno").value+'&_hidManId='+userid;
		if(item == ('I2')){
			document.getElementById("_areMemo").disabled = true;
			frm._areMemo.value = "值班";
		} else if (item == ('I3')){
			document.getElementById("_areMemo").disabled = true;
			frm._areMemo.value = "值退";
		} else if (item == ('I4')){
			document.getElementById("_areMemo").disabled = false;
		} else {
			frm._areMemo.value = "";

		}
	}
